import React, { useState, useEffect, useMemo } from 'react';
import { AuthUser, User, Venda, Indicacao, Meta, Empresa } from './types';
import { cloud } from './services/firebase';
import { FORMAT_BRL, INDICACAO_STATUS_MAP, VENDA_STATUS_MAP } from './constants';
import Layout from './components/Layout';
import AiAssistant from './components/AiAssistant';

const App: React.FC = () => {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [user, setUser] = useState<AuthUser | null>(null);
  const [activeSection, setActiveSection] = useState('dashboard');

  const [loginForm, setLoginForm] = useState({ username: '', password: '' });
  const [searchTerm, setSearchTerm] = useState('');
  const [salesmanFilter, setSalesmanFilter] = useState('TODOS');

  // Global Data State
  const [vendas, setVendas] = useState<Venda[]>([]);
  const [usuarios, setUsuarios] = useState<User[]>([]);
  const [metas, setMetas] = useState<Meta[]>([]);
  const [indicacoes, setIndicacoes] = useState<Indicacao[]>([]);
  const [empresas, setEmpresas] = useState<Empresa[]>([]);

  // Selection/UI State
  const [selectedVendas, setSelectedVendas] = useState<string[]>([]);
  const [modalType, setModalType] = useState<'venda' | 'indicacao' | 'usuario' | 'empresa' | 'meta' | null>(null);
  const [editingItem, setEditingItem] = useState<any>(null);
  const [aiLead, setAiLead] = useState<any>(null);

  useEffect(() => {
    const unsubVendas = cloud.subscribeVendas(setVendas);
    const unsubUsers = cloud.subscribeUsuarios(setUsuarios);
    const unsubMetas = cloud.subscribeMetas(setMetas);
    const unsubIndicacoes = cloud.subscribeIndicacoes(setIndicacoes);
    const unsubEmpresas = cloud.subscribeEmpresas(setEmpresas);

    return () => {
      unsubVendas();
      unsubUsers();
      unsubMetas();
      unsubIndicacoes();
      unsubEmpresas();
    };
  }, []);

  const handleLogin = () => {
    const uI = loginForm.username.trim().toLowerCase();
    const pI = loginForm.password.trim();

    if (uI === 'admin' && pI === 'admin123') {
      const admin: AuthUser = { nome: 'ADMIN MASTER', setor: 'ADMIN', isAdmin: true, login: 'admin', comissao: 100 };
      setUser(admin);
      setIsAuthenticated(true);
    } else {
      const found = usuarios.find(u => (u.login || '').toLowerCase() === uI && u.senha === pI);
      if (found) {
        const authUser: AuthUser = { ...found, isAdmin: found.setor === 'ADMIN' };
        setUser(authUser);
        setIsAuthenticated(true);
      } else {
        alert('Credenciais inválidas');
      }
    }
  };

  const logout = () => {
    setIsAuthenticated(false);
    setUser(null);
    setLoginForm({ username: '', password: '' });
  };

  // Helper functions
  const moveVenda = async (item: Venda, direction: 'left' | 'right') => {
    const currentIndex = VENDA_STATUS_MAP.indexOf(item.status);
    const nextIndex = direction === 'right' ? currentIndex + 1 : currentIndex - 1;
    if (nextIndex >= 0 && nextIndex < VENDA_STATUS_MAP.length) {
      await cloud.updateStatus('vendas', item.id!, VENDA_STATUS_MAP[nextIndex]);
    }
  };

  const moveIndicacao = async (item: Indicacao, direction: 'left' | 'right') => {
    const currentIndex = INDICACAO_STATUS_MAP.indexOf(item.status);
    const nextIndex = direction === 'right' ? currentIndex + 1 : currentIndex - 1;
    if (nextIndex >= 0 && nextIndex < INDICACAO_STATUS_MAP.length) {
      await cloud.updateStatus('indicacoes', item.id!, INDICACAO_STATUS_MAP[nextIndex]);
    }
  };

  const filteredVendas = useMemo(() => {
    let list = user?.isAdmin ? vendas : vendas.filter(v => v.vendedor === user?.nome);
    if (user?.isAdmin && salesmanFilter !== 'TODOS') list = list.filter(v => v.vendedor === salesmanFilter);
    if (searchTerm) {
      const low = searchTerm.toLowerCase();
      list = list.filter(v => (v.cliente||'').toLowerCase().includes(low) || (v.vendedor||'').toLowerCase().includes(low));
    }
    return list;
  }, [vendas, user, searchTerm, salesmanFilter]);

  const filteredIndicacoes = useMemo(() => {
    let list = user?.isAdmin ? indicacoes : indicacoes.filter(i => i.vendedor === user?.nome);
    if (user?.isAdmin && salesmanFilter !== 'TODOS') list = list.filter(i => i.vendedor === salesmanFilter);
    if (searchTerm) {
      const low = searchTerm.toLowerCase();
      list = list.filter(i => (i.cliente||'').toLowerCase().includes(low) || (i.veiculo||'').toLowerCase().includes(low));
    }
    return list;
  }, [indicacoes, user, searchTerm, salesmanFilter]);

  // --- COMPONENTES DE SEÇÃO ---

  const Dashboard = () => {
    const stats = useMemo(() => {
      const now = new Date();
      const startOfMonth = new Date(now.getFullYear(), now.getMonth(), 1).getTime();
      const startOfDay = new Date(now.getFullYear(), now.getMonth(), now.getDate()).getTime();

      const baseVendas = user?.isAdmin ? vendas : vendas.filter(v => v.vendedor === user?.nome);
      const mesVendas = baseVendas.filter(v => v.dataCriacao >= startOfMonth);
      const mesPagas = mesVendas.filter(v => v.status === 'Pagamento Efetuado');
      const hojePagas = baseVendas.filter(v => v.dataCriacao >= startOfDay && v.status === 'Pagamento Efetuado');

      const companyMeta = metas.find(m => m.vendedor === 'EMPRESA_VM_SEGUROS');
      const userMeta = metas.find(m => m.vendedor === user?.nome);

      // LÓGICA DE SOMA AUTOMÁTICA SOLICITADA: Somente 'Pagamento Efetuado'
      const globalMesVendas = vendas.filter(v => v.dataCriacao >= startOfMonth);
      const globalPagas = globalMesVendas.filter(v => v.status === 'Pagamento Efetuado');

      return {
        vendasDia: hojePagas.length,
        premioDia: hojePagas.reduce((acc, v) => acc + Number(v.valor || 0), 0),
        vendasMes: mesPagas.length,
        premioMes: mesPagas.reduce((acc, v) => acc + Number(v.valor || 0), 0),
        comissaoMes: mesPagas.reduce((acc, v) => acc + Number(v.comissao_vendedor || 0), 0),

        globalVendasCount: globalPagas.length,
        globalPremioTotal: globalPagas.reduce((acc, v) => acc + Number(v.valor || 0), 0),
        globalComissaoTotal: globalPagas.reduce((acc, v) => acc + Number(v.comissao_cheia || 0), 0),

        companyMeta,
        userMeta
      };
    }, [vendas, metas, user]);

    return (
      <div className="space-y-8 animate-in fade-in duration-500">
        <div className="flex justify-between items-center">
          <h2 className="text-4xl font-black uppercase text-white tracking-tighter">Cockpit Geral</h2>
          <div className="flex gap-2">
            <button onClick={() => setModalType('indicacao')} className="bg-yellow-500 text-black px-6 py-3 rounded-2xl font-black uppercase text-[10px] hover:scale-105 transition-all">Novo Lead</button>
            <button onClick={() => setModalType('venda')} className="bg-blue-600 text-white px-6 py-3 rounded-2xl font-black uppercase text-[10px] hover:scale-105 transition-all">Lançar Produção</button>
          </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
          <div className="bg-[#111827] p-8 rounded-[2.5rem] border border-gray-800 border-l-4 border-l-blue-500 shadow-xl">
            <p className="text-gray-500 text-[10px] font-black uppercase mb-1">Vendas Pagas (Hoje)</p>
            <h3 className="text-5xl font-black text-white">{stats.vendasDia}</h3>
          </div>
          <div className="bg-[#111827] p-8 rounded-[2.5rem] border border-gray-800 border-l-4 border-l-green-500 shadow-xl">
            <p className="text-gray-500 text-[10px] font-black uppercase mb-1">Prêmio Pago (Hoje)</p>
            <h3 className="text-2xl font-black text-green-500">{FORMAT_BRL(stats.premioDia)}</h3>
          </div>
          <div className="bg-[#111827] p-8 rounded-[2.5rem] border border-gray-800 border-l-4 border-l-yellow-500 shadow-xl">
            <p className="text-gray-500 text-[10px] font-black uppercase mb-1">Vendas Pagas (Mês)</p>
            <h3 className="text-5xl font-black text-white">{stats.vendasMes}</h3>
          </div>
          <div className="bg-[#111827] p-8 rounded-[2.5rem] border border-gray-800 border-l-4 border-l-white shadow-xl">
            <p className="text-gray-500 text-[10px] font-black uppercase mb-1">Prêmio Pago (Mês)</p>
            <h3 className="text-2xl font-black text-white">{FORMAT_BRL(stats.premioMes)}</h3>
          </div>
        </div>

        {user?.isAdmin && stats.companyMeta && (
          <div className="bg-[#111827] p-10 rounded-[3.5rem] border border-purple-500/20 shadow-2xl relative overflow-hidden">
            <div className="absolute top-0 right-0 p-8 opacity-5"><i className="fas fa-building text-9xl"></i></div>
            <h3 className="text-xl font-black uppercase text-white mb-10 flex items-center gap-3">
              <i className="fas fa-chart-line text-purple-500"></i> Performance Consolidada (VM SEGUROS)
            </h3>
            <div className="grid grid-cols-1 md:grid-cols-3 gap-10">
              <div className="space-y-4">
                <p className="text-gray-500 text-[10px] font-black uppercase">Vendas Pagas Empresa</p>
                <h4 className="text-3xl font-black text-white">{stats.globalVendasCount} / <span className="text-gray-600">{stats.companyMeta.meta_qtd}</span></h4>
                <div className="h-2 bg-gray-900 rounded-full overflow-hidden">
                  <div className="h-full bg-purple-500" style={{ width: `${Math.min((stats.globalVendasCount/stats.companyMeta.meta_qtd)*100, 100)}%` }}></div>
                </div>
              </div>
              <div className="space-y-4">
                <p className="text-gray-500 text-[10px] font-black uppercase">Prêmio Bruto Acumulado (Pago)</p>
                <h4 className="text-2xl font-black text-white">{FORMAT_BRL(stats.globalPremioTotal)}</h4>
                <div className="h-2 bg-gray-900 rounded-full overflow-hidden">
                  <div className="h-full bg-green-500" style={{ width: `${Math.min((stats.globalPremioTotal/stats.companyMeta.meta_premio)*100, 100)}%` }}></div>
                </div>
              </div>
              <div className="space-y-4">
                <p className="text-gray-500 text-[10px] font-black uppercase">Comissão Bruta Empresa (Paga)</p>
                <h4 className="text-2xl font-black text-white">{FORMAT_BRL(stats.globalComissaoTotal)}</h4>
                <div className="h-2 bg-gray-900 rounded-full overflow-hidden">
                  <div className="h-full bg-yellow-500" style={{ width: `${Math.min((stats.globalComissaoTotal/stats.companyMeta.meta_salario)*100, 100)}%` }}></div>
                </div>
              </div>
            </div>
          </div>
        )}
      </div>
    );
  };

  const KanbanVendas = () => (
    <div className="flex gap-6 overflow-x-auto pb-6 scrollbar-thin h-[calc(100vh-180px)]">
      {VENDA_STATUS_MAP.map(status => (
        <div key={status} className="kanban-column flex flex-col w-80 bg-[#111827] rounded-[2rem] border border-gray-800 p-4">
          <div className="flex justify-between items-center mb-6 px-2">
            <h3 className="text-[10px] font-black uppercase text-gray-400 tracking-widest">{status}</h3>
            <span className="bg-gray-800 text-white text-[9px] font-black px-3 py-1 rounded-full">
              {filteredVendas.filter(v => v.status === status).length}
            </span>
          </div>
          <div className="flex-1 space-y-4 overflow-y-auto pr-2 scrollbar-thin">
            {filteredVendas.filter(v => v.status === status).map(v => (
              <div key={v.id} className="bg-[#1e293b] p-5 rounded-3xl border border-gray-700 shadow-sm group hover:border-blue-500/50 transition-all">
                <div className="flex justify-between items-start mb-3">
                  <p className="text-xs font-black text-white uppercase leading-tight">{v.cliente}</p>
                  {v.suhai && <span className="s-suhai-pulse text-[8px]">SUHAI</span>}
                </div>
                <p className="text-[10px] text-gray-400 uppercase font-bold mb-1">{v.empresa || 'SUHAI'}</p>
                <p className="text-[11px] font-black text-blue-400 mb-4">{FORMAT_BRL(v.valor)}</p>

                <div className="flex justify-between items-center mt-4 pt-4 border-t border-gray-700">
                  <button onClick={() => moveVenda(v, 'left')} className="p-2 text-gray-500 hover:text-white"><i className="fas fa-chevron-left text-xs"></i></button>
                  <div className="flex gap-2">
                    <button onClick={() => { setEditingItem(v); setModalType('venda'); }} className="p-2 text-gray-500 hover:text-blue-400"><i className="fas fa-edit text-xs"></i></button>
                    <button onClick={() => cloud.apagar('vendas', v.id!)} className="p-2 text-gray-500 hover:text-red-400"><i className="fas fa-trash text-xs"></i></button>
                  </div>
                  <button onClick={() => moveVenda(v, 'right')} className="p-2 text-gray-500 hover:text-white"><i className="fas fa-chevron-right text-xs"></i></button>
                </div>
              </div>
            ))}
          </div>
        </div>
      ))}
    </div>
  );

  const KanbanIndicacoes = () => (
    <div className="flex gap-6 overflow-x-auto pb-6 scrollbar-thin h-[calc(100vh-180px)]">
      {INDICACAO_STATUS_MAP.map(status => (
        <div key={status} className="kanban-column flex flex-col w-80 bg-[#111827] rounded-[2rem] border border-gray-800 p-4">
          <div className="flex justify-between items-center mb-6 px-2">
            <h3 className="text-[10px] font-black uppercase text-gray-400 tracking-widest">{status}</h3>
            <span className="bg-gray-800 text-white text-[9px] font-black px-3 py-1 rounded-full">
              {filteredIndicacoes.filter(i => i.status === status).length}
            </span>
          </div>
          <div className="flex-1 space-y-4 overflow-y-auto pr-2 scrollbar-thin">
            {filteredIndicacoes.filter(i => i.status === status).map(i => (
              <div key={i.id} className="bg-[#1e293b] p-5 rounded-3xl border border-gray-700 shadow-sm hover:border-yellow-500/50 transition-all">
                <div className="flex justify-between items-start mb-3">
                  <p className="text-xs font-black text-white uppercase leading-tight">{i.cliente}</p>
                  <button onClick={() => setAiLead(i)} className="text-blue-400 text-xs hover:scale-125 transition-all"><i className="fas fa-robot"></i></button>
                </div>
                <p className="text-[10px] text-gray-400 uppercase font-bold mb-1">{i.veiculo}</p>
                <div className="flex gap-2 mt-4">
                  <button onClick={() => moveIndicacao(i, 'left')} className="flex-1 bg-gray-800 p-2 rounded-xl text-[8px] font-black uppercase"><i className="fas fa-arrow-left"></i></button>
                  <button onClick={() => { setEditingItem(i); setModalType('indicacao'); }} className="flex-1 bg-gray-800 p-2 rounded-xl text-[8px] font-black uppercase">Editar</button>
                  <button onClick={() => moveIndicacao(i, 'right')} className="flex-1 bg-gray-800 p-2 rounded-xl text-[8px] font-black uppercase"><i className="fas fa-arrow-right"></i></button>
                </div>
                <a href={`https://wa.me/${i.tel.replace(/\D/g,'')}`} target="_blank" className="block w-full text-center bg-green-600/20 text-green-500 p-3 rounded-2xl text-[9px] font-black uppercase mt-3 hover:bg-green-600 hover:text-white transition-all">WhatsApp</a>
              </div>
            ))}
          </div>
        </div>
      ))}
    </div>
  );

  const FinanceiroView = () => {
    const list = filteredVendas.filter(v => v.status === 'Pagamento Efetuado');
    return (
      <div className="bg-[#111827] rounded-[3rem] border border-gray-800 overflow-hidden">
        <div className="p-8 border-b border-gray-800 flex justify-between items-center">
          <h2 className="text-xl font-black uppercase text-white">Extrato de Produção Confirmada</h2>
          <div className="bg-green-500/10 text-green-500 px-6 py-2 rounded-full font-black text-xs">Total: {FORMAT_BRL(list.reduce((a,b)=>a+Number(b.valor),0))}</div>
        </div>
        <table className="w-full text-left">
          <thead className="bg-[#0f172a] text-[10px] font-black uppercase text-gray-500">
            <tr>
              <th className="p-6">Cliente</th>
              <th className="p-6">Vendedor</th>
              <th className="p-6">Prêmio</th>
              <th className="p-6">Comissão Empresa</th>
              <th className="p-6">Comissão Vendedor</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-gray-800">
            {list.map(v => (
              <tr key={v.id} className="text-xs text-white hover:bg-white/5 transition-all">
                <td className="p-6 font-bold uppercase">{v.cliente}</td>
                <td className="p-6 uppercase">{v.vendedor}</td>
                <td className="p-6 font-mono">{FORMAT_BRL(v.valor)}</td>
                <td className="p-6 font-mono text-purple-400">{FORMAT_BRL(v.comissao_cheia)}</td>
                <td className="p-6 font-mono text-green-400">{FORMAT_BRL(v.comissao_vendedor)}</td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    );
  };

  const VendedoresView = () => (
    <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
      {usuarios.filter(u => u.setor === 'VENDEDOR').map(u => (
        <div key={u.id} className="bg-[#111827] p-8 rounded-[3rem] border border-gray-800 relative">
          <button onClick={() => { setEditingItem(u); setModalType('usuario'); }} className="absolute top-6 right-6 text-gray-500 hover:text-white"><i className="fas fa-edit"></i></button>
          <div className="w-16 h-16 bg-blue-600 rounded-2xl flex items-center justify-center text-2xl font-black mb-6">{u.nome[0]}</div>
          <h3 className="text-lg font-black uppercase text-white mb-1">{u.nome}</h3>
          <p className="text-[10px] text-gray-500 font-bold uppercase mb-4">Acesso: {u.login}</p>
          <div className="bg-gray-800/50 p-4 rounded-2xl">
            <p className="text-[10px] text-gray-500 uppercase font-black mb-1">Comissão Acordada</p>
            <p className="text-xl font-black text-blue-400">{u.comissao}%</p>
          </div>
          <button onClick={() => cloud.apagar('usuarios', u.id!)} className="mt-6 w-full text-[10px] font-black uppercase text-red-500 hover:bg-red-500/10 p-3 rounded-xl transition-all">Remover Vendedor</button>
        </div>
      ))}
      <button onClick={() => setModalType('usuario')} className="border-4 border-dashed border-gray-800 rounded-[3rem] flex flex-col items-center justify-center p-8 hover:border-blue-500 transition-all text-gray-700 hover:text-blue-500">
        <i className="fas fa-user-plus text-4xl mb-4"></i>
        <span className="font-black uppercase text-xs">Novo Vendedor</span>
      </button>
    </div>
  );

  const ConfiguracoesView = () => (
    <div className="max-w-2xl space-y-8">
      <div className="bg-[#111827] p-10 rounded-[3rem] border border-gray-800">
        <h3 className="text-xl font-black uppercase text-white mb-8">Empresas / Seguradoras</h3>
        <div className="space-y-4">
          <div className="flex gap-4">
            <input id="new-emp-name" type="text" placeholder="Nome da Seguradora" className="flex-1 bg-gray-900 border border-gray-800 p-4 rounded-2xl text-xs font-bold uppercase" />
            <button onClick={() => {
              const el = document.getElementById('new-emp-name') as HTMLInputElement;
              if (el.value) cloud.salvarEmpresa({ nome: el.value.toUpperCase() });
              el.value = '';
            }} className="bg-blue-600 px-8 rounded-2xl font-black uppercase text-[10px]">Adicionar</button>
          </div>
          <div className="grid grid-cols-2 gap-2 mt-6">
            {empresas.map(e => (
              <div key={e.id} className="bg-gray-800/50 p-3 rounded-xl flex justify-between items-center">
                <span className="text-[10px] font-black uppercase text-gray-300">{e.nome}</span>
                <button onClick={() => cloud.apagar('empresas', e.id!)} className="text-red-500 text-[10px]"><i className="fas fa-times"></i></button>
              </div>
            ))}
          </div>
        </div>
      </div>
    </div>
  );

  // --- MODAIS ---

  const ModalWrapper = ({ title, children, onClose, onSave }: any) => (
    <div className="fixed inset-0 bg-black/90 backdrop-blur-sm z-[200] flex items-center justify-center p-4">
      <div className="bg-[#111827] w-full max-w-xl rounded-[3rem] border border-gray-800 shadow-2xl overflow-hidden animate-in zoom-in duration-300">
        <div className="p-8 border-b border-gray-800 flex justify-between items-center">
          <h3 className="text-xl font-black uppercase text-white tracking-tighter">{title}</h3>
          <button onClick={onClose} className="text-gray-500 hover:text-white"><i className="fas fa-times text-xl"></i></button>
        </div>
        <div className="p-8 max-h-[70vh] overflow-y-auto scrollbar-thin space-y-6">
          {children}
        </div>
        <div className="p-8 bg-gray-900/50 border-t border-gray-800 flex justify-end gap-4">
          <button onClick={onClose} className="text-[10px] font-black uppercase text-gray-500 hover:text-white px-6 py-4 rounded-2xl">Cancelar</button>
          <button onClick={onSave} className="bg-blue-600 text-white px-10 py-4 rounded-2xl font-black uppercase text-[10px] hover:bg-blue-500 transition-all">Salvar Alterações</button>
        </div>
      </div>
    </div>
  );

  const VendaModal = () => {
    const [form, setForm] = useState<Venda>(editingItem || {
      cliente: '', tel: '', vendedor: user?.nome || '', empresa: 'SUHAI', valor: 0, 
      comissao_cheia: 0, comissao_vendedor: 0, suhai: true, status: 'Fazer Vistoria', dataCriacao: Date.now()
    });

    const handleSave = async () => {
      if (!form.cliente || !form.vendedor) return alert('Preencha os campos obrigatórios');
      await cloud.salvarVenda(form);
      setModalType(null);
      setEditingItem(null);
    };

    return (
      <ModalWrapper title={editingItem ? "Editar Lançamento" : "Nova Produção"} onClose={() => setModalType(null)} onSave={handleSave}>
        <div className="grid grid-cols-2 gap-4">
          <div className="col-span-2 space-y-2">
            <label className="text-[10px] font-black uppercase text-gray-500">Nome do Segurado</label>
            <input type="text" className="w-full bg-gray-900 border border-gray-800 p-4 rounded-2xl text-xs font-bold uppercase" value={form.cliente} onChange={e => setForm({...form, cliente: e.target.value.toUpperCase()})} />
          </div>
          <div className="space-y-2">
            <label className="text-[10px] font-black uppercase text-gray-500">Telefone</label>
            <input type="text" className="w-full bg-gray-900 border border-gray-800 p-4 rounded-2xl text-xs font-bold" value={form.tel} onChange={e => setForm({...form, tel: e.target.value})} />
          </div>
          <div className="space-y-2">
            <label className="text-[10px] font-black uppercase text-gray-500">Vendedor</label>
            <select className="w-full bg-gray-900 border border-gray-800 p-4 rounded-2xl text-xs font-bold" value={form.vendedor} onChange={e => setForm({...form, vendedor: e.target.value})}>
              <option value="">Selecione</option>
              {usuarios.filter(u => u.setor === 'VENDEDOR').map(u => <option key={u.id} value={u.nome}>{u.nome}</option>)}
            </select>
          </div>
          <div className="space-y-2">
            <label className="text-[10px] font-black uppercase text-gray-500">Seguradora</label>
            <select className="w-full bg-gray-900 border border-gray-800 p-4 rounded-2xl text-xs font-bold" value={form.empresa} onChange={e => setForm({...form, empresa: e.target.value})}>
              <option value="SUHAI">SUHAI</option>
              {empresas.map(e => <option key={e.id} value={e.nome}>{e.nome}</option>)}
            </select>
          </div>
          <div className="space-y-2">
            <label className="text-[10px] font-black uppercase text-gray-500">Prêmio Total</label>
            <input type="number" className="w-full bg-gray-900 border border-gray-800 p-4 rounded-2xl text-xs font-bold" value={form.valor} onChange={e => {
              const val = Number(e.target.value);
              setForm({...form, valor: val, comissao_cheia: val * 0.15, comissao_vendedor: (val * 0.15) * 0.4});
            }} />
          </div>
          <div className="space-y-2">
            <label className="text-[10px] font-black uppercase text-gray-500">C. Bruta Empresa</label>
            <input type="number" className="w-full bg-gray-900 border border-gray-800 p-4 rounded-2xl text-xs font-bold" value={form.comissao_cheia} onChange={e => setForm({...form, comissao_cheia: Number(e.target.value)})} />
          </div>
          <div className="space-y-2">
            <label className="text-[10px] font-black uppercase text-gray-500">Comissão Vendedor</label>
            <input type="number" className="w-full bg-gray-900 border border-gray-800 p-4 rounded-2xl text-xs font-bold" value={form.comissao_vendedor} onChange={e => setForm({...form, comissao_vendedor: Number(e.target.value)})} />
          </div>
          <div className="col-span-2 space-y-2">
             <label className="text-[10px] font-black uppercase text-gray-500">Status Atual</label>
             <select className="w-full bg-gray-900 border border-gray-800 p-4 rounded-2xl text-xs font-bold" value={form.status} onChange={e => setForm({...form, status: e.target.value as any})}>
               {VENDA_STATUS_MAP.map(s => <option key={s} value={s}>{s}</option>)}
             </select>
          </div>
        </div>
      </ModalWrapper>
    );
  };

  const IndicacaoModal = () => {
    const [form, setForm] = useState<Indicacao>(editingItem || {
      cliente: '', tel: '', veiculo: '', vendedor: user?.nome || '', suhai: true, info: '', 
      status: 'NOVA INDICAÇÃO', dataCriacao: Date.now()
    });

    const handleSave = async () => {
      await cloud.salvarIndicacao(form);
      setModalType(null);
      setEditingItem(null);
    };

    return (
      <ModalWrapper title={editingItem ? "Editar Lead" : "Novo Lead"} onClose={() => setModalType(null)} onSave={handleSave}>
        <div className="grid grid-cols-2 gap-4">
          <div className="col-span-2 space-y-2">
            <label className="text-[10px] font-black uppercase text-gray-500">Nome do Lead</label>
            <input type="text" className="w-full bg-gray-900 border border-gray-800 p-4 rounded-2xl text-xs font-bold uppercase" value={form.cliente} onChange={e => setForm({...form, cliente: e.target.value.toUpperCase()})} />
          </div>
          <div className="space-y-2">
            <label className="text-[10px] font-black uppercase text-gray-500">Telefone / WhatsApp</label>
            <input type="text" className="w-full bg-gray-900 border border-gray-800 p-4 rounded-2xl text-xs font-bold" value={form.tel} onChange={e => setForm({...form, tel: e.target.value})} />
          </div>
          <div className="space-y-2">
            <label className="text-[10px] font-black uppercase text-gray-500">Veículo</label>
            <input type="text" className="w-full bg-gray-900 border border-gray-800 p-4 rounded-2xl text-xs font-bold uppercase" value={form.veiculo} onChange={e => setForm({...form, veiculo: e.target.value.toUpperCase()})} />
          </div>
          <div className="col-span-2 space-y-2">
            <label className="text-[10px] font-black uppercase text-gray-500">Informações Adicionais</label>
            <textarea className="w-full bg-gray-900 border border-gray-800 p-4 rounded-2xl text-xs font-bold h-32" value={form.info} onChange={e => setForm({...form, info: e.target.value})}></textarea>
          </div>
        </div>
      </ModalWrapper>
    );
  };

  // Auth Guard
  if (!isAuthenticated) {
    return (
      <div className="flex items-center justify-center min-h-screen bg-[#0b0f1a] p-4">
        <div className="bg-[#111827] p-10 rounded-[3rem] border border-gray-800 w-full max-w-md shadow-2xl animate-in zoom-in duration-500">
          <h2 className="text-3xl font-black uppercase mb-8 text-center tracking-tighter text-white">Login Cloud CRM</h2>
          <div className="space-y-4">
            <input type="text" placeholder="Usuário" className="w-full p-4 bg-[#0f172a] border border-gray-800 rounded-2xl text-xs font-bold text-white uppercase" value={loginForm.username} onChange={e => setLoginForm({...loginForm, username: e.target.value})} />
            <input type="password" placeholder="Senha" className="w-full p-4 bg-[#0f172a] border border-gray-800 rounded-2xl text-xs font-bold text-white" value={loginForm.password} onChange={e => setLoginForm({...loginForm, password: e.target.value})} />
            <button onClick={handleLogin} className="w-full bg-blue-600 hover:bg-blue-500 p-4 rounded-2xl font-black uppercase text-xs text-white transition-all shadow-lg shadow-blue-900/20">Acessar CRM</button>
          </div>
        </div>
      </div>
    );
  }

  return (
    <Layout user={user!} onLogout={logout} activeSection={activeSection} setActiveSection={setActiveSection}>
      <div className="max-w-[1600px] mx-auto space-y-8">
        {/* Barra de Busca Global */}
        {!['dashboard', 'performance', 'configuracoes'].includes(activeSection) && (
          <div className="flex gap-4 bg-[#111827] p-4 rounded-3xl border border-gray-800">
            <div className="flex-1 relative">
              <i className="fas fa-search absolute left-5 top-1/2 -translate-y-1/2 text-gray-600"></i>
              <input type="text" placeholder="PESQUISAR CLIENTE, VEÍCULO OU VENDEDOR..." className="w-full bg-gray-900/50 pl-14 pr-6 py-4 rounded-2xl text-[10px] font-black uppercase text-white outline-none focus:border-blue-500 border border-transparent transition-all" value={searchTerm} onChange={e => setSearchTerm(e.target.value)} />
            </div>
            {user?.isAdmin && (
              <select className="bg-gray-900/50 px-6 rounded-2xl text-[10px] font-black uppercase text-gray-400 border border-transparent" value={salesmanFilter} onChange={e => setSalesmanFilter(e.target.value)}>
                <option value="TODOS">TODOS VENDEDORES</option>
                {usuarios.filter(u => u.setor === 'VENDEDOR').map(u => <option key={u.id} value={u.nome}>{u.nome}</option>)}
              </select>
            )}
          </div>
        )}

        {/* Renderização de Seções */}
        {activeSection === 'dashboard' && <Dashboard />}
        {activeSection === 'kanban-vendas' && <KanbanVendas />}
        {activeSection === 'kanban-indicacoes' && <KanbanIndicacoes />}
        {activeSection === 'comissao' && <FinanceiroView />}
        {activeSection === 'vendedores' && <VendedoresView />}
        {activeSection === 'configuracoes' && <ConfiguracoesView />}
        {activeSection === 'lead-suhai-page' && (
          <div className="space-y-6">
            <h2 className="text-4xl font-black uppercase text-green-500">Exclusivo Suhai</h2>
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
               {vendas.filter(v => v.suhai).map(v => (
                 <div key={v.id} className="bg-[#111827] p-8 rounded-[3rem] border border-green-500/20">
                    <p className="text-xs font-black text-white uppercase">{v.cliente}</p>
                    <p className="text-[10px] text-green-500 font-bold uppercase mt-1">Apólice Suhai Detectada</p>
                 </div>
               ))}
            </div>
          </div>
        )}

        {/* Modal de Performance Master */}
        {activeSection === 'performance' && (
          <div className="space-y-10">
            <h2 className="text-4xl font-black uppercase text-purple-400">Master Performance</h2>
            <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
              {usuarios.filter(u => u.setor === 'VENDEDOR').map(u => {
                const mesVendas = vendas.filter(v => v.vendedor === u.nome && v.status === 'Pagamento Efetuado');
                const meta = metas.find(m => m.vendedor === u.nome);
                return (
                  <div key={u.id} className="bg-[#111827] p-10 rounded-[3.5rem] border border-gray-800 relative group overflow-hidden">
                    <div className="absolute top-0 right-0 p-8 opacity-5 group-hover:opacity-20 transition-all"><i className="fas fa-medal text-8xl"></i></div>
                    <h4 className="text-xl font-black text-white uppercase mb-6">{u.nome}</h4>
                    <div className="space-y-6">
                      <div>
                        <div className="flex justify-between text-[10px] font-black text-gray-500 uppercase mb-2"><span>Vendas Pagas</span><span>{mesVendas.length} / {meta?.meta_qtd || 0}</span></div>
                        <div className="h-2 bg-gray-900 rounded-full overflow-hidden"><div className="h-full bg-blue-500" style={{width: `${Math.min((mesVendas.length/(meta?.meta_qtd||1))*100, 100)}%`}}></div></div>
                      </div>
                      <div>
                        <div className="flex justify-between text-[10px] font-black text-gray-500 uppercase mb-2"><span>Prêmio Produzido</span><span>{FORMAT_BRL(mesVendas.reduce((a,b)=>a+Number(b.valor),0))}</span></div>
                        <div className="h-2 bg-gray-900 rounded-full overflow-hidden"><div className="h-full bg-green-500" style={{width: `${Math.min((mesVendas.reduce((a,b)=>a+Number(b.valor),0)/(meta?.meta_premio||1))*100, 100)}%`}}></div></div>
                      </div>
                    </div>
                  </div>
                );
              })}
            </div>
          </div>
        )}
      </div>

      {/* Modais Ativos */}
      {modalType === 'venda' && <VendaModal />}
      {modalType === 'indicacao' && <IndicacaoModal />}
      {aiLead && <AiAssistant lead={aiLead} onClose={() => setAiLead(null)} />}

      {modalType === 'usuario' && (
        <ModalWrapper title="Gerenciar Vendedor" onClose={() => setModalType(null)} onSave={async () => {
          const name = (document.getElementById('u-name') as HTMLInputElement).value;
          const log = (document.getElementById('u-login') as HTMLInputElement).value;
          const pass = (document.getElementById('u-pass') as HTMLInputElement).value;
          const com = Number((document.getElementById('u-com') as HTMLInputElement).value);
          await cloud.salvarUsuario({ ...editingItem, nome: name, login: log, senha: pass, comissao: com, setor: 'VENDEDOR' });
          setModalType(null);
          setEditingItem(null);
        }}>
          <div className="space-y-4">
            <input id="u-name" type="text" placeholder="Nome Completo" defaultValue={editingItem?.nome} className="w-full bg-gray-900 border border-gray-800 p-4 rounded-2xl text-xs font-bold uppercase" />
            <input id="u-login" type="text" placeholder="Login de Acesso" defaultValue={editingItem?.login} className="w-full bg-gray-900 border border-gray-800 p-4 rounded-2xl text-xs font-bold" />
            <input id="u-pass" type="password" placeholder="Senha" defaultValue={editingItem?.senha} className="w-full bg-gray-900 border border-gray-800 p-4 rounded-2xl text-xs font-bold" />
            <input id="u-com" type="number" placeholder="Comissão %" defaultValue={editingItem?.comissao} className="w-full bg-gray-900 border border-gray-800 p-4 rounded-2xl text-xs font-bold" />
          </div>
        </ModalWrapper>
      )}

      {activeSection === 'metas' && (
        <div className="bg-[#111827] p-10 rounded-[3rem] border border-gray-800">
           <h3 className="text-xl font-black uppercase text-white mb-8">Definição de Metas de Equipe</h3>
           <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              {[...usuarios.filter(u=>u.setor==='VENDEDOR'), {nome: 'EMPRESA_VM_SEGUROS'}].map((target: any) => {
                const m = metas.find(mt => mt.vendedor === (target.nome || target));
                return (
                  <div key={target.nome || target} className="bg-gray-900/50 p-6 rounded-3xl border border-gray-800 space-y-4">
                    <p className="text-[10px] font-black uppercase text-blue-400">{target.nome || target}</p>
                    <div className="grid grid-cols-3 gap-2">
                       <input type="number" placeholder="Vendas" className="bg-black border border-gray-800 p-3 rounded-xl text-[10px] text-white" defaultValue={m?.meta_qtd} onBlur={(e) => cloud.salvarMeta({...m, vendedor: target.nome || target, meta_qtd: Number(e.target.value)})} />
                       <input type="number" placeholder="Prêmio" className="bg-black border border-gray-800 p-3 rounded-xl text-[10px] text-white" defaultValue={m?.meta_premio} onBlur={(e) => cloud.salvarMeta({...m, vendedor: target.nome || target, meta_premio: Number(e.target.value)})} />
                       <input type="number" placeholder="Faturam." className="bg-black border border-gray-800 p-3 rounded-xl text-[10px] text-white" defaultValue={m?.meta_salario} onBlur={(e) => cloud.salvarMeta({...m, vendedor: target.nome || target, meta_salario: Number(e.target.value)})} />
                    </div>
                  </div>
                )
              })}
           </div>
        </div>
      )}
    </Layout>
  );
};

export default App;
